  // Get words by rank range
  static List<WordModel> getWordsByRankRange(int startRank, int endRank) {
    return getAllWords()
        .where((word) => word.rank >= startRank && word.rank < endRank)
        .toList();
  }
  
  // Get random words for quiz from a rank range
  static List<WordModel> getRandomWordsForLevel(int levelNumber, int count) {
    final level = LevelModel.generate(levelNumber);
    final availableWords = getWordsByRankRange(level.startRank, level.endRank);
    
    if (availableWords.length < count) {
      return availableWords;
    }
    
    availableWords.shuffle();
    return availableWords.take(count).toList();
  }
